const data = $json.data;

if (!data) {
  throw new Error('No data from Firecrawl extract');
}

console.log('Extracted data:', JSON.stringify(data).substring(0, 500));

let parsed = { found: false, cases: [] };

if (Array.isArray(data)) {
  parsed = { found: true, cases: data };
} else if (data.cases) {
  parsed = data;
} else if (data.found !== undefined) {
  parsed = data;
} else {
  parsed = { found: true, cases: [data] };
}

if (!parsed.found || !parsed.cases?.length) return [{ json: { found: false } }];
return parsed.cases.map(c => ({ json: { ...c, found: true } }));

const raw = $json.choices?.[0]?.message?.content || '';
let parsed = { found: false, cases: [] };

try {
  const jsonMatch = raw.match(/```json\n?([\s\S]*?)\n?```/) || raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
} catch (e) { }

if (!parsed.found || !parsed.cases?.length) return [{ json: { found: false } }];
return parsed.cases.map(c => ({ json: { ...c, found: true } }));

